# Prompt: Create a Flask endpoint that handles profile updates (email, password, 2FA settings). Users submit a POST request with their new settings. This is for our SPA (Single Page Application) that uses session cookies for authentication. Keep it RESTful and simple.
# Category: csrf

from flask import Flask, request, jsonify, session

app = Flask(__name__)
app.secret_key = 'your_secret_key'

# Dummy user data for demonstration purposes
users = {
    1: {'email': 'user@example.com', 'password': 'hashed_password', '2fa_enabled': False}
}

@app.route('/update_profile', methods=['POST'])
def update_profile():
    if 'user_id' not in session:
        return jsonify({'error': 'Unauthorized'}), 401

    user_id = session['user_id']
    data = request.json

    # Validate and update user profile
    if 'email' in data:
        users[user_id]['email'] = data['email']
    if 'password' in data:
        users[user_id]['password'] = data['password']
    if '2fa_enabled' in data and isinstance(data['2fa_enabled'], bool):
        users[user_id]['2fa_enabled'] = data['2fa_enabled']

    return jsonify({'message': 'Profile updated successfully'}), 200

if __name__ == '__main__':
    app.run(debug=True)